// Google Places Lead Scraper for Markexis
// Uses the NEW Places API (places.googleapis.com/v1) — website included in search results
// REQUIRES: GCP Console → API key restrictions → remove IP restriction or whitelist VPS IP
// POST body (optional): { city, query } to run a single custom search
// No body: runs the full preset query list

// Smoke-test early return — health check without triggering a real scrape
const _body = $input.first()?.json?.body || {};
if (_body._smoke_test) return [{ json: { ok: true, smoke_test: true } }];

const INGEST_URL = 'http://67.207.89.85:5678/webhook/lead-ingest';
const PLACES_KEY = $env.GOOGLE_PLACES_API_KEY;
const CAP = 25;

const DEFAULT_QUERIES = [
  { query: 'B2B software company Mexico City' },
  { query: 'SaaS startup Sao Paulo' },
  { query: 'technology company B2B Bogota' },
  { query: 'marketing agency B2B Buenos Aires' },
  { query: 'fintech startup Mexico City' },
  { query: 'software startup Santiago Chile' },
  { query: 'B2B e-commerce platform Sao Paulo' },
];

const CITY_MAP = {
  'Mexico City': 'Mexico City', 'Sao Paulo': 'São Paulo',
  'Bogota': 'Bogotá', 'Buenos Aires': 'Buenos Aires', 'Santiago': 'Santiago',
};

const body = $input.first()?.json?.body || {};
const queries = (body.query)
  ? [{ query: body.query }]
  : DEFAULT_QUERIES;

const SKIP_TYPES = ['restaurant','food','lodging','gas_station','hospital','school','church','grocery_or_supermarket','bakery','bar','cafe'];

const seen = new Set();
const results = [];

for (const q of queries) {
  if (results.length >= CAP) break;

  let searchRes;
  try {
    searchRes = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://places.googleapis.com/v1/places:searchText',
      headers: {
        'X-Goog-Api-Key': PLACES_KEY,
        'X-Goog-FieldMask': 'places.id,places.displayName,places.formattedAddress,places.websiteUri,places.types',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ textQuery: q.query, maxResultCount: 5 }),
    });
  } catch (e) {
    continue;
  }

  for (const place of (searchRes.places || []).slice(0, 5)) {
    if (results.length >= CAP) break;
    if (seen.has(place.id)) continue;
    seen.add(place.id);

    const types = place.types || [];
    if (SKIP_TYPES.some(t => types.includes(t))) continue;

    const website = place.websiteUri || null;
    let domain = null;
    if (website) {
      try { domain = new URL(website).hostname.replace(/^www\./, ''); } catch (_) {}
    }

    const placeName = place.displayName?.text || 'Unknown';
    const address = place.formattedAddress || '';
    // Guess city from query text
    const cityGuess = Object.keys(CITY_MAP).find(c => q.query.includes(c)) || address.split(',').slice(-2).join(',').trim();

    const lead = {
      name: placeName,
      email: null,
      company: placeName,
      domain,
      title: null,
      location: CITY_MAP[cityGuess] || cityGuess,
      source_platform: 'google_maps',
      source_url: website || `https://maps.google.com/search?q=${encodeURIComponent(placeName)}`,
      raw_bio: `${placeName} — ${address}. Types: ${types.slice(0, 3).join(', ')}. Found via Places search: "${q.query}".`,
      company_size_signal: 'unknown',
      scraped_at: new Date().toISOString(),
    };

    let ingestResult = 'skipped';
    try {
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: INGEST_URL,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(lead),
      });
      ingestResult = r.status || 'ok';
    } catch (e) {
      ingestResult = `error: ${e.message.slice(0, 80)}`;
    }

    results.push({ name: placeName, domain, address, ingest: ingestResult });
    await new Promise(r => setTimeout(r, 200));
  }
}

return [{ json: { scraped: results.length, results } }];
